class Solution {
public:
    bool increasingTriplet(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n; ++i) {
        if(i != 0 && (i != n)){
        if((nums[i+1] < nums[i]) && (nums[i-1] < nums[i]))
            return(true);
        }}

        return(false);
    }
};

